"""
install_trial_conversion.py
Save to: C:\\vantro\\install_trial_conversion.py
Run from C:\\vantro:    python install_trial_conversion.py

Adds the trial -> paid conversion flow.
Idempotent.
"""
import base64, json, os, sys

CRON_PATH = os.path.join("app", "api", "cron", "trial-conversion", "route.ts")
PAYWALL_PATH = os.path.join("components", "billing", "PaywallOverlay.tsx")
GUARD_PATH = os.path.join("lib", "billing-guard.ts")
VERCEL_JSON = "vercel.json"
ADMIN_PAGE = os.path.join("app", "admin", "page.tsx")

CRON_B64 = ""
PAYWALL_B64 = ""
GUARD_B64 = ""
VERCEL_B64 = "ewogICJjcm9ucyI6IFsKICAgIHsKICAgICAgInBhdGgiOiAiL2FwaS9jcm9uL3RyaWFsLWNvbnZlcnNpb24iLAogICAgICAic2NoZWR1bGUiOiAiMzAgMjMgKiAqICoiCiAgICB9CiAgXQp9"

def write_file(path, b64, label):
    full = os.path.join(os.getcwd(), path)
    if os.path.exists(full):
        print(f"  exists, skipping: {path}")
        return
    os.makedirs(os.path.dirname(full), exist_ok=True)
    with open(full, "w", encoding="utf-8", newline="\n") as f:
        f.write(base64.b64decode(b64).decode("utf-8"))
    print(f"  wrote: {path} ({label})")

def merge_vercel_json():
    full = os.path.join(os.getcwd(), VERCEL_JSON)
    new_config = json.loads(base64.b64decode(VERCEL_B64).decode("utf-8"))
    if not os.path.exists(full):
        with open(full, "w", encoding="utf-8") as f:
            json.dump(new_config, f, indent=2)
        print(f"  wrote: {VERCEL_JSON}")
        return
    with open(full, "r", encoding="utf-8") as f:
        existing = json.load(f)
    existing_crons = existing.get("crons", [])
    target_path = "/api/cron/trial-conversion"
    if any(c.get("path") == target_path for c in existing_crons):
        print(f"  cron already registered in {VERCEL_JSON}")
        return
    existing_crons.append(new_config["crons"][0])
    existing["crons"] = existing_crons
    with open(full, "w", encoding="utf-8") as f:
        json.dump(existing, f, indent=2)
    print(f"  patched: {VERCEL_JSON} (added cron)")

def patch_admin_for_paywall():
    if not os.path.exists(ADMIN_PAGE):
        print(f"  ERROR: {ADMIN_PAGE} not found")
        return
    with open(ADMIN_PAGE, "r", encoding="utf-8") as f:
        src = f.read()
    if "paywall_overlay_v1" in src:
        print("  admin page already patched")
        return

    OLD_B64 = ""
    NEW_B64 = ""
    old = base64.b64decode(OLD_B64).decode("utf-8")
    new = base64.b64decode(NEW_B64).decode("utf-8")
    if old in src:
        src = src.replace(old, new)
        print("  patched: removed billing redirect, set trialExpiredAndUnpaid")
    else:
        print("  WARN: trial check anchor not found")

    old_render = "        company={company}"
    new_render = "        company={company}\n        trialExpiredAndUnpaid={trialExpiredAndUnpaid}"
    if old_render in src and "trialExpiredAndUnpaid={" not in src.replace(old_render, ""):
        src = src.replace(old_render, new_render)
        print("  patched: passed trialExpiredAndUnpaid prop")

    with open(ADMIN_PAGE, "w", encoding="utf-8", newline="\n") as f:
        f.write(src)

def main():
    cwd = os.getcwd()
    if not cwd.lower().endswith("vantro"):
        print("WARNING: not in C:\\vantro")
        sys.exit(1)
    print("Stage 1/3: writing new files...")
    write_file(CRON_PATH, CRON_B64, "trial conversion cron")
    write_file(PAYWALL_PATH, PAYWALL_B64, "paywall overlay")
    write_file(GUARD_PATH, GUARD_B64, "billing guard helper")
    print("Stage 2/3: vercel cron config...")
    merge_vercel_json()
    print("Stage 3/3: admin page paywall integration...")
    patch_admin_for_paywall()
    print()
    print("Done. Manual steps remain:")
    print("  1. Run install_trial_conversion.sql in Supabase")
    print("  2. Add CRON_SECRET env var in Vercel (any random string)")
    print("  3. Add tier selection step to app/onboarding/page.tsx (manual)")
    print("  4. Render PaywallOverlay in AdminDashboard (manual)")

if __name__ == "__main__":
    main()